#!/usr/bin/env python3
"""
Eagle 3D Streaming - Deploy v5.0
Run: python3 deploy_v5.py
"""
import base64, os, shutil
from datetime import datetime

APP_B64 = ""

DASHBOARD_PY = """# dashboard.py - Redirect to app.py (v5)
import os, runpy
os.environ.setdefault('STREAMLIT_SERVER_HEADLESS', 'true')
runpy.run_path('app.py', run_name='__main__')
"""

CONFIG_TOML = """[server]
headless = true
maxUploadSize = 200

[browser]
gatherUsageStats = false

[theme]
base = "dark"
primaryColor = "#00D4FF"
backgroundColor = "#0B1120"
secondaryBackgroundColor = "#162032"
textColor = "#E8EDF5"
"""

SECRETS_TOML = """# Add your API keys below
GROQ_API_KEY = "your-key"
GEMINI_API_KEY = "your-key"
"""

print()
print("=" * 60)
print("  Eagle 3D Streaming - KPI Dashboard v5.0 Deploy")
print("=" * 60)
print()
if os.path.exists("app.py"):
    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    shutil.copy2("app.py", f"app.py.backup_{ts}")
if os.path.exists("dashboard.py"):
    shutil.copy2("dashboard.py", f"dashboard.py.backup_{ts}")
print("  [1/6] Backed up old files")

with open("app.py", "wb") as f:
    f.write(base64.b64decode(APP_B64))
print("  [2/6] Wrote new app.py (v5.0)")

with open("dashboard.py", "w") as f:
    f.write(DASHBOARD_PY)
print("  [3/6] Wrote dashboard.py redirect")

os.makedirs(".streamlit", exist_ok=True)
with open(".streamlit/config.toml", "w") as f:
    f.write(CONFIG_TOML)
print("  [4/6] Fixed config.toml")

# Only write secrets.toml if it does NOT exist (preserve user keys)
if not os.path.exists(".streamlit/secrets.toml"):
    with open(".streamlit/secrets.toml", "w") as f:
        f.write(SECRETS_TOML)
    print("  [5/6] Created secrets.toml (add your API keys!)")
else:
    print("  [5/6] secrets.toml exists (preserved your keys)")

import subprocess
subprocess.run(["git", "config", "user.email", "eagle3d@automation.dev"], capture_output=True)
subprocess.run(["git", "config", "user.name", "Eagle3D Automation"], capture_output=True)
subprocess.run(["git", "add", "app.py", "dashboard.py", ".streamlit/config.toml"], capture_output=True)
subprocess.run(["git", "commit", "-m", "v5.0: fix fillcolor crash, remove hardcoded keys, manual override, telegram, all features"], capture_output=True, text=True)
print("  [6/6] Git committed")

print()
print("=" * 60)
print("  DONE! Now push:")
print()
print("    git fetch origin")
print("    git push --force origin main")
print("=" * 60)